function Header({ isLoggedIn, user, onLogin, onLogout }) {
  // 1. Decide what to render
  let authControl;
  if (isLoggedIn) {
    authControl = <UserMenu user={user} onLogout={onLogout} />;
  } else {
    authControl = <LoginButton onClick={onLogin} label="Sign In" />;
  }

  // 2. Use it in JSX
  return (
    <header className="site-header">
      <Logo />
      <Nav />
      {authControl}
    </header>
  );
}

function FetchStatus({ status, data, error }) {
  let content;

  if (status === 'loading') {
    content = <LoadingSpinner />;
  } else if (status === 'error') {
    content = <ErrorBanner message={error.message} retry={reload} />;
  } else if (data.length === 0) {
    content = <EmptyState message="No results found." />;
  } else {
    content = <DataTable rows={data} />;
  }

  return (
    <section aria-live="polite">
      <SectionHeader />
      {content}
    </section>
  );
}

// const + ternary — good for two-branch cases
const greeting = isLoggedIn
  ? <WelcomeMessage name={user.name} />
  : <GuestBanner />

// let + if/else — required for three or more branches
let badge;
if (count === 0) {
  badge = null;
} else if (count > 99) {
  badge = <Badge label="99+" />;
} else {
  badge = <Badge label={String(count)} />;
}

function NewsletterPage({ isSubscribed, email }) {
  const subscribeButton = isSubscribed
    ? null
    : <SubscribeButton email={email} />;

  return (
    <div>
      {/* Show subscribe CTA at the top of the page */}
      <Hero>{subscribeButton}</Hero>

      <ArticleList />

      {/* And again at the bottom */}
      <PageFooter>
        {subscribeButton}
      </PageFooter>
    </div>
  );
}

function PricingCard({ plan, billingCycle, promoCode }) {
  // Compute props separately
  const basePrice = plan.prices[billingCycle];
  const discount = promoCode ? getDiscount(promoCode) : 0;
  const finalPrice = basePrice * (1 - discount);
  const priceLabel = formatCurrency(finalPrice, plan.currency);

  // Decide which badge to show
  let badge = null;
  if (plan.isBestValue) {
    badge = <BestValueBadge />;
  } else if (discount > 0) {
    badge = <DiscountBadge percent={Math.round(discount * 100)} />;
  }

  // Clean JSX
  return (
    <div className="pricing-card">
      {badge}
      <h2>{plan.name}</h2>
      <p className="price">{priceLabel}<span>/{billingCycle}</span></p>
      <FeatureList features={plan.features} />
      <CheckoutButton planId={plan.id} promoCode={promoCode} />
    </div>
  );
}

function Toolbar({ canShare, canExport, canDelete, item }) {
  // null means "render nothing" — valid JSX
  const shareBtn = canShare ? <ShareButton item={item} /> : null;
  const exportBtn = canExport ? <ExportButton item={item} /> : null;
  const deleteBtn = canDelete ? <DeleteButton item={item} /> : null;

  return (
    <div className="toolbar">
      {shareBtn}
      {exportBtn}
      {deleteBtn}
    </div>
  );
}

import { ReactNode } from 'react';

function Panel({ status }: { status: 'loading' | 'error' | 'success' }) {
  // Explicit type annotation — TS verifies all branches assign a valid ReactNode
  let content: ReactNode;

  if (status === 'loading') {
    content = <Spinner />;
  } else if (status === 'error') {
    content = <ErrorState />;
  } else {
    content = <SuccessView />;
  }

  return <div>{content}</div>;
}

// ReactNode includes JSX.Element, null, undefined, string, number
// JSX.Element | null — more restrictive, fine for JSX-only variables

// Named after what the variable represents
const userMenu = isAdmin ? <AdminMenu /> : <UserMenu />;
const errorPanel = error ? <ErrorPanel error={error} /> : null;
const actionButton = isEditing ? <SaveButton /> : <EditButton />;

// Named 'content' or 'body' for the main slot
const content = items.length > 0 ? <ItemGrid items={items} /> : <EmptyState />;

// Named after the slot in the layout
const sidebar = showFilters ? <FilterPanel /> : null;
const header = isFullScreen ? null : <PageHeader title={title} />;

// Used directly inline (compact form — still an element variable)
return <Layout sidebar={showFilters ? <FilterPanel /> : null} />

import { render, screen } from '@testing-library/react';

describe('Header', () => {
  test('shows user menu when logged in', () => {
    render(<Header isLoggedIn={true} user={{ name: 'Alice' }} onLogout={jest.fn()} />);
    expect(screen.getByRole('navigation', { name: /user menu/i })).toBeInTheDocument();
    expect(screen.queryByRole('button', { name: /sign in/i })).not.toBeInTheDocument();
  });

  test('shows login button when not logged in', () => {
    render(<Header isLoggedIn={false} onLogin={jest.fn()} />);
    expect(screen.getByRole('button', { name: /sign in/i })).toBeInTheDocument();
    expect(screen.queryByRole('navigation', { name: /user menu/i })).not.toBeInTheDocument();
  });
});

describe('FetchStatus', () => {
  test('renders spinner during load', () => {
    render(<FetchStatus status="loading" data={[]} error={null} />);
    expect(screen.getByRole('status')).toBeInTheDocument();
  });

  test('renders error banner on error', () => {
    render(<FetchStatus status="error" data={[]} error={{ message: 'timeout' }} />);
    expect(screen.getByText(/timeout/)).toBeInTheDocument();
  });

  test('renders empty state when no results', () => {
    render(<FetchStatus status="success" data={[]} error={null} />);
    expect(screen.getByText(/no results/i)).toBeInTheDocument();
  });
});

function AlertBanner({ type, message }) {
  // switch on an enum-like string — easy to extend
  let icon;
  switch (type) {
    case 'success':
      icon = <CheckCircleIcon className="icon-green" />;
      break;
    case 'warning':
      icon = <TriangleAlertIcon className="icon-amber" />;
      break;
    case 'error':
      icon = <XCircleIcon className="icon-red" />;
      break;
    default:
      icon = <InfoIcon className="icon-blue" />;
  }

  return (
    <div className={`alert alert-${type}`} role="alert">
      {icon}
      <span>{message}</span>
    </div>
  );
}

function AppShell({ children }) {
  return (
    <div className="app">
      <Sidebar />
      <main>{children}</main>
    </div>
  );
}

// Layout component with explicit slots
function TwoColumnLayout({ header, sidebar, content, footer }) {
  return (
    <div className="layout">
      <header>{header}</header>
      <aside>{sidebar}</aside>
      <main>{content}</main>
      <footer>{footer}</footer>
    </div>
  );
}

// Caller decides what goes in each slot
function DashboardPage({ user, stats, isAdmin }) {
  const sidebarContent = isAdmin ? <AdminNav user={user} /> : <UserNav user={user} />;
  const statsPanel = stats ? <StatsGrid data={stats} /> : <LoadingGrid />;

  return (
    <TwoColumnLayout
      header={<PageHeader title="Dashboard" user={user} />}
      sidebar={sidebarContent}
      content={statsPanel}
      footer={<SiteFooter />}
    />
  );
}

import { useMemo } from 'react';

function DataReport({ rows, filter, sortKey }) {
  // Sorting 10,000 rows on every keystroke is expensive
  const tableContent = useMemo(() => {
    const sorted = [...rows]
      .filter(r => r.name.includes(filter))
      .sort((a, b) => a[sortKey].localeCompare(b[sortKey]));

    return sorted.length > 0
      ? <ReportTable rows={sorted} />
      : <EmptyReport />;
  }, [rows, filter, sortKey]);

  return (
    <section>
      <FilterBar />
      {tableContent}
    </section>
  );
}

// ❌ Overusing element variables — adds noise without clarity
function UserCard({ user }) {
  const avatar = <img src={user.avatar} alt={user.name} />;
  const name = <h2>{user.name}</h2>;             // trivial — leave inline
  const email = <p>{user.email}</p>;             // trivial — leave inline
  const editBtn = <EditButton userId={user.id} />; // trivial — leave inline

  return (
    <div>
      {avatar}{name}{email}{editBtn}
    </div>
  );
}

// ✓ Only hoist what genuinely needs a decision
function UserCard({ user, isOwner }) {
  const actionArea = isOwner
    ? <div><EditButton userId={user.id} /><DeleteButton userId={user.id} /></div>
    : null;

  return (
    <div>
      <img src={user.avatar} alt={user.name} />
      <h2>{user.name}</h2>
      <p>{user.email}</p>
      {actionArea}
    </div>
  );
}
